	`id` int AUTO_INCREMENT NOT NULL,
	`equipment_id` int NOT NULL,
	`booking_id` int NOT NULL,
	`notes` text,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `equipment_bookings_id` PRIMARY KEY(`id`)
);

ALTER TABLE `studio_rooms` ADD COLUMN IF NOT EXISTS `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP;
ALTER TABLE `studio_bookings` ADD COLUMN IF NOT EXISTS `room_id` int;

